// SimpleCAD ヘッドレス検証スクリプト（Playwright/Chromium）
// 実行: node test/verify.mjs
import { chromium } from 'playwright';
import { fileURLToPath, pathToFileURL } from 'url';
import { dirname, join } from 'path';

const __dirname = dirname(fileURLToPath(import.meta.url));
const url = pathToFileURL(join(__dirname, '..', 'index.html')).href;

let pass = 0, fail = 0;
const results = [];
function check(name, cond, detail = '') {
  if (cond) { pass++; results.push(`  ✅ ${name}`); }
  else { fail++; results.push(`  ❌ ${name}${detail ? ' — ' + detail : ''}`); }
}

// キャンバス上の (clientX,clientY) を rect 基準で渡してマウス作図
async function drawDrag(page, box, x1, y1, x2, y2) {
  await page.mouse.move(box.x + x1, box.y + y1);
  await page.mouse.down();
  await page.mouse.move(box.x + (x1 + x2) / 2, box.y + (y1 + y2) / 2);
  await page.mouse.move(box.x + x2, box.y + y2);
  await page.mouse.up();
}

const browser = await chromium.launch();
const page = await browser.newPage({ viewport: { width: 1000, height: 700 } });

const consoleErrors = [];
page.on('console', m => { if (m.type() === 'error') consoleErrors.push(m.text()); });
page.on('pageerror', e => consoleErrors.push('pageerror: ' + e.message));
page.on('dialog', d => d.accept()); // confirm()は承認

await page.goto(url);
await page.waitForFunction(() => window.SimpleCAD && typeof window.SimpleCAD.shapeCount === 'function', null, { timeout: 5000 });
// 自動保存の復元を消してクリーン状態に
await page.evaluate(() => window.SimpleCAD.clearAll());

const canvas = await page.$('#cv');
const box = await canvas.boundingBox();

// --- A: ロード/初期化 ---
check('ページがコンソールエラーなくロードされる', consoleErrors.length === 0, consoleErrors.join(' | '));
check('window.SimpleCAD が公開されている', await page.evaluate(() => !!window.SimpleCAD));
const startupSchemaArrayIteratorPage = await browser.newPage({ viewport: { width: 600, height: 420 } });
const startupSchemaArrayIteratorErrors = [];
startupSchemaArrayIteratorPage.on('console', m => { if (m.type() === 'error') startupSchemaArrayIteratorErrors.push(m.text()); });
startupSchemaArrayIteratorPage.on('pageerror', e => startupSchemaArrayIteratorErrors.push('pageerror: ' + e.message));
await startupSchemaArrayIteratorPage.addInitScript(() => {
  const originalIterator = Array.prototype[Symbol.iterator];
  const hasValue = (arr, value) => {
    const len = Number(arr && arr.length) || 0;
    for (let i = 0; i < len; i++) {
      if (arr[i] === value) return true;
    }
    return false;
  };
  const schemaLike = arr =>
    (hasValue(arr, 'line') && hasValue(arr, 'polyline') && hasValue(arr, 'image')) ||
    (hasValue(arr, 'strokeWidth') && hasValue(arr, 'miterLimit')) ||
    (hasValue(arr, 'points') && hasValue(arr, 'closed')) ||
    (hasValue(arr, 'visible') && hasValue(arr, 'locked') && hasValue(arr, 'name'));
  Object.defineProperty(Array.prototype, Symbol.iterator, {
    configurable: true,
    writable: true,
    value() {
      if (schemaLike(this)) throw new Error('startup schema array iterator unavailable');
      return originalIterator.call(this);
    },
  });
});
await startupSchemaArrayIteratorPage.goto(url);
let startupSchemaArrayIterator = {};
try {
  await startupSchemaArrayIteratorPage.waitForFunction(
    () => window.SimpleCAD && typeof window.SimpleCAD.shapeCount === 'function' && document.getElementById('cv').width > 0,
    null,
    { timeout: 5000, polling: 50 },
  );
  startupSchemaArrayIterator = await startupSchemaArrayIteratorPage.evaluate(() => {
    window.SimpleCAD.loadJSON({
      shapes: [{ id: 'schemaArrRect', type: 'rect', x: 1, y: 2, w: 30, h: 20, stroke: '#000', strokeWidth: 1, fill: null }],
      layers: [{ id: 'L1', name: 'レイヤー1', visible: true, locked: false }],
      activeLayer: 'L1',
    });
    window.SimpleCAD.draw();
    const dumped = window.SimpleCAD.dumpJSON();
    return {
      exposed: !!window.SimpleCAD,
      count: window.SimpleCAD.shapeCount(),
      shapeId: dumped.shapes[0] && dumped.shapes[0].id,
      layerId: dumped.layers[0] && dumped.layers[0].id,
      canvasWidth: document.getElementById('cv').width,
      canvasHeight: document.getElementById('cv').height,
    };
  });
} catch (e) {
  startupSchemaArrayIterator = { exposed: false, error: e && e.message };
}
await startupSchemaArrayIteratorPage.close();
check('起動時スキーマ配列iteratorが壊れていてもアプリは公開されデータ正規化を継続する',
  startupSchemaArrayIterator.exposed === true &&
  startupSchemaArrayIterator.count === 1 &&
  startupSchemaArrayIterator.shapeId === 'schemaArrRect' &&
  startupSchemaArrayIterator.layerId === 'L1' &&
  startupSchemaArrayIterator.canvasWidth > 0 &&
  startupSchemaArrayIterator.canvasHeight > 0 &&
  startupSchemaArrayIteratorErrors.length === 0,
  JSON.stringify({ startupSchemaArrayIterator, startupSchemaArrayIteratorErrors }));
