await startupBrokenApiPage.addInitScript(() => {
  const originalAddEventListener = EventTarget.prototype.addEventListener;
  EventTarget.prototype.addEventListener = function (type, listener, options) {
    const stack = String(new Error().stack || '');
    if (stack.includes('index.html') &&
        (this === window || this === document || this instanceof HTMLCanvasElement ||
        this instanceof HTMLButtonElement || this instanceof HTMLTextAreaElement)) {
      throw new Error('startup addEventListener unavailable');
    }
    return originalAddEventListener.call(this, type, listener, options);
  };
  try {
    Object.defineProperty(window, 'requestAnimationFrame', {
      configurable: true,
      value() { throw new Error('startup requestAnimationFrame unavailable'); },
    });
  } catch (e) {}
});
await startupBrokenApiPage.goto(url);
