const startupBrokenSwatchDomPage = await browser.newPage({ viewport: { width: 600, height: 420 } });
const startupBrokenSwatchDomErrors = [];
startupBrokenSwatchDomPage.on('console', m => { if (m.type() === 'error') startupBrokenSwatchDomErrors.push(m.text()); });
startupBrokenSwatchDomPage.on('pageerror', e => startupBrokenSwatchDomErrors.push('pageerror: ' + e.message));
await startupBrokenSwatchDomPage.addInitScript(() => {
  const originalGetElementById = Document.prototype.getElementById;
  Document.prototype.getElementById = function (id) {
    if (String(id) === 'fillSwatches') return null;
    return originalGetElementById.call(this, id);
  };
  const originalSetAttribute = Element.prototype.setAttribute;
  Element.prototype.setAttribute = function (name, value) {
    const stack = String(new Error().stack || '');
    if (stack.includes('index.html') && this instanceof HTMLButtonElement && ['aria-label', 'title'].includes(String(name))) {
      throw new Error('startup swatch setAttribute unavailable');
    }
    return originalSetAttribute.call(this, name, value);
  };
  const htmlButtonStyle = Object.getOwnPropertyDescriptor(HTMLElement.prototype, 'style');
  if (!htmlButtonStyle || htmlButtonStyle.configurable !== false) {
    Object.defineProperty(HTMLButtonElement.prototype, 'style', {
      configurable: true,
      get() {
        const stack = String(new Error().stack || '');
        if (stack.includes('index.html')) throw new Error('startup swatch style unavailable');
        return htmlButtonStyle && htmlButtonStyle.get ? htmlButtonStyle.get.call(this) : undefined;
      },
    });
  }
  const textContent = Object.getOwnPropertyDescriptor(Node.prototype, 'textContent');
  if (textContent && textContent.configurable !== false) {
    Object.defineProperty(HTMLButtonElement.prototype, 'textContent', {
      configurable: true,
      get() { return textContent.get ? textContent.get.call(this) : ''; },
      set(value) {
        const stack = String(new Error().stack || '');
        if (stack.includes('index.html')) throw new Error('startup swatch textContent unavailable');
        if (textContent.set) textContent.set.call(this, value);
      },
    });
  }
  const originalAppend = Element.prototype.append;
  Element.prototype.append = function (...nodes) {
    const stack = String(new Error().stack || '');
    if (stack.includes('index.html') && this && this.id === 'swatches') {
      throw new Error('startup swatch append unavailable');
    }
    return originalAppend.call(this, ...nodes);
  };
  const originalAppendChild = Node.prototype.appendChild;
  Node.prototype.appendChild = function (node) {
    const stack = String(new Error().stack || '');
    if (stack.includes('index.html') && this && this.id === 'swatches') {
      throw new Error('startup swatch appendChild unavailable');
    }
    return originalAppendChild.call(this, node);
  };
});
