await startupBrokenQueryPage.addInitScript(() => {
  const patch = (proto, name) => {
    const original = proto && proto[name];
    if (typeof original !== 'function') return;
    proto[name] = function (...args) {
      const stack = String(new Error().stack || '');
      if (stack.includes('index.html')) throw new Error('startup query API unavailable');
      return original.apply(this, args);
    };
  };
  patch(Document.prototype, 'querySelector');
  patch(Document.prototype, 'querySelectorAll');
  patch(Element.prototype, 'querySelector');
  patch(Element.prototype, 'querySelectorAll');
});
await startupBrokenQueryPage.goto(url);
