const cspDataScriptProbe = await cspProbePage.evaluate(() => new Promise(resolve => {
  window.__simpleCadCspProbeRan = false;
  let settled = false;
  const finish = result => {
    if (settled) return;
    settled = true;
    document.removeEventListener('securitypolicyviolation', onViolation);
    resolve({ ...result, ran: window.__simpleCadCspProbeRan === true });
  };
  const onViolation = event => {
    if (String(event.effectiveDirective || '').includes('script-src')) {
      finish({ blocked: true, directive: event.effectiveDirective, blockedURI: event.blockedURI });
    }
  };
  document.addEventListener('securitypolicyviolation', onViolation);
  const script = document.createElement('script');
  script.src = "data:text/javascript,window.__simpleCadCspProbeRan%3Dtrue";
  script.onload = () => setTimeout(() => finish({ blocked: false, loaded: true }), 50);
  script.onerror = () => setTimeout(() => finish({ blocked: false, error: true }), 50);
  document.head.appendChild(script);
  setTimeout(() => finish({ blocked: false, timeout: true }), 700);
}));
