const shadowFocusTarget = await page.evaluate(() => {
  const host = document.createElement('div');
  document.body.appendChild(host);
  const root = host.attachShadow({ mode: 'open' });
  const input = document.createElement('input');
  root.appendChild(input);
  const connectedContains = document.contains(input);
  const focusResult = typeof window.focusElement === 'function' ? window.focusElement(input) : false;
  const activeInside = root.activeElement === input;

  const detachedHost = document.createElement('div');
  const detachedRoot = detachedHost.attachShadow({ mode: 'open' });
  const detachedInput = document.createElement('input');
  detachedRoot.appendChild(detachedInput);
  const detachedFocusResult = typeof window.focusElement === 'function' ? window.focusElement(detachedInput) : false;
  host.remove();
  return { connectedContains, focusResult, activeInside, detachedFocusResult };
});
