const exportShapeIteratorFixture = await page.evaluate(() => window.SimpleCAD.dumpJSON());
const exportShapeIteratorRecoveryErrorsBefore = consoleErrors.length;
const exportShapeIteratorRecovery = await page.evaluate(() => {
  const originalIterator = Object.getOwnPropertyDescriptor(Array.prototype, Symbol.iterator);
  const shouldBreak = arr => {
    try {
      const len = Number(arr && arr.length);
      if (!Number.isFinite(len) || len <= 0) return false;
      for (let i = 0; i < len; i++) {
        const item = arr[i];
        if (!item || typeof item !== 'object') continue;
        const id = String(item.id || '');
        const name = String(item.name || '');
        if (id.indexOf('iterExport') === 0 || name.indexOf('ITER_EXPORT') === 0) return true;
      }
    } catch (e) {}
    return false;
  };
  const restoreIterator = () => {
    if (originalIterator) Object.defineProperty(Array.prototype, Symbol.iterator, originalIterator);
  };
  try {
    window.SimpleCAD.clearAll();
    window.SimpleCAD.state.layers = [{ id: 'ITER_EXPORT_LAYER', name: 'ITER_EXPORT_LAYER', visible: true, locked: false }];
    window.SimpleCAD.state.activeLayer = 'ITER_EXPORT_LAYER';
    window.SimpleCAD.addShape({ id: 'iterExportLine', type: 'line', x1: 0, y1: 0, x2: 30, y2: 0, stroke: '#000000', strokeWidth: 1, fill: null, layer: 'ITER_EXPORT_LAYER' });
    window.SimpleCAD.addShape({ id: 'iterExportDim', type: 'dim', x1: 0, y1: 10, x2: 30, y2: 10, text: '30.0', stroke: '#000000', strokeWidth: 1, fill: null, layer: 'ITER_EXPORT_LAYER' });
    window.SimpleCAD.addShape({ id: 'iterExportPoly', type: 'polyline', points: [{ x: 0, y: 20 }, { x: 15, y: 30 }, { x: 30, y: 20 }], closed: true, stroke: '#000000', strokeWidth: 1, fill: '#ffffff', layer: 'ITER_EXPORT_LAYER' });
    const beforeView = { ...window.SimpleCAD.state.view };
    Object.defineProperty(Array.prototype, Symbol.iterator, {
      configurable: true,
      writable: true,
      value: function () {
        if (shouldBreak(this)) throw new Error('broken export iterator');
        return originalIterator.value.call(this);
      },
    });
    const svg = window.SimpleCAD.buildSVGString();
    const dxf = window.SimpleCAD.buildDXF();
    window.SimpleCAD.fitView();
    const drawRendered = window.SimpleCAD.draw();
    const afterView = { ...window.SimpleCAD.state.view };
    return {
      ok: true,
      svgHasLine: svg.includes('<line'),
      svgHasText: svg.includes('<text'),
      svgHasPolygon: svg.includes('<polygon'),
      dxfHasLine: dxf.includes('LINE'),
      dxfHasPolyline: dxf.includes('LWPOLYLINE'),
      dxfHasLayer: dxf.includes('ITER_EXPORT_LAYER'),
      drawRendered,
      viewChanged: afterView.scale !== beforeView.scale || afterView.offsetX !== beforeView.offsetX || afterView.offsetY !== beforeView.offsetY,
    };
  } catch (e) {
    return { ok: false, message: e && e.message };
  } finally {
    restoreIterator();
  }
});
await page.evaluate(data => window.SimpleCAD.loadJSON(data), exportShapeIteratorFixture);
await page.waitForTimeout(20);
const exportShapeIteratorRecoveryErrors = consoleErrors.slice(exportShapeIteratorRecoveryErrorsBefore);
check('SVG/DXF書き出しとfitViewは図形/レイヤー配列iterator破損下でも継続する',
  exportShapeIteratorRecovery.ok === true &&
  exportShapeIteratorRecovery.svgHasLine === true &&
  exportShapeIteratorRecovery.svgHasText === true &&
  exportShapeIteratorRecovery.svgHasPolygon === true &&
  exportShapeIteratorRecovery.dxfHasLine === true &&
  exportShapeIteratorRecovery.dxfHasPolyline === true &&
  exportShapeIteratorRecovery.dxfHasLayer === true &&
  exportShapeIteratorRecovery.drawRendered === true &&
  exportShapeIteratorRecovery.viewChanged === true &&
  exportShapeIteratorRecoveryErrors.length === 0,
  JSON.stringify({ exportShapeIteratorRecovery, exportShapeIteratorRecoveryErrors }));

