// --- I: ピンチズーム（合成タッチ pointer イベント） ---
await page.evaluate(() => window.SimpleCAD.clearAll());
const beforeScale = await page.evaluate(() => window.SimpleCAD.state.view.scale);
await page.evaluate(() => {
  const cv = document.getElementById('cv');
  const r = cv.getBoundingClientRect();
  const mk = (type, id, x, y) => cv.dispatchEvent(new PointerEvent(type, {
    pointerId: id, pointerType: 'touch', clientX: r.left + x, clientY: r.top + y,
    bubbles: true, cancelable: true, isPrimary: id === 1,
  }));
  // 2本指を中央付近から外側へ広げる→ズームイン
  mk('pointerdown', 1, 400, 350); mk('pointerdown', 2, 500, 350);
  for (let i = 1; i <= 5; i++) { mk('pointermove', 1, 400 - i * 20, 350); mk('pointermove', 2, 500 + i * 20, 350); }
  mk('pointerup', 1, 300, 350); mk('pointerup', 2, 600, 350);
});
const afterScale = await page.evaluate(() => window.SimpleCAD.state.view.scale);
check('2本指ピンチでズーム倍率が増加', afterScale > beforeScale, `before=${beforeScale} after=${afterScale}`);
const pinchMapIteratorErrorsBefore = consoleErrors.length;
const pinchMapIteratorRecovery = await page.evaluate(() => {
  window.SimpleCAD.clearAll();
  window.SimpleCAD.state.view = { scale: 1, offsetX: 0, offsetY: 0 };
  window.SimpleCAD.draw();
  const before = window.SimpleCAD.state.view.scale;
  const cv = document.getElementById('cv');
  const r = cv.getBoundingClientRect();
  const mk = (type, id, x, y) => cv.dispatchEvent(new PointerEvent(type, {
    pointerId: id, pointerType: 'touch', clientX: r.left + x, clientY: r.top + y,
    bubbles: true, cancelable: true, isPrimary: id === 1,
  }));
  const proto = Map.prototype;
  const saved = {
    values: proto.values,
    iterator: Object.getOwnPropertyDescriptor(proto, Symbol.iterator),
  };
  let restored = false;
  let threw = false;
  let error = '';
  const restore = () => {
    proto.values = saved.values;
    if (saved.iterator) Object.defineProperty(proto, Symbol.iterator, saved.iterator);
    else delete proto[Symbol.iterator];
    restored = true;
  };
  try {
    proto.values = function () { throw new Error('broken pinch map values'); };
    Object.defineProperty(proto, Symbol.iterator, {
      configurable: true,
      writable: true,
      value: function () { throw new Error('broken pinch map iterator'); },
    });
    mk('pointerdown', 1, 420, 360); mk('pointerdown', 2, 520, 360);
    for (let i = 1; i <= 4; i++) { mk('pointermove', 1, 420 - i * 25, 360); mk('pointermove', 2, 520 + i * 25, 360); }
    mk('pointerup', 1, 320, 360); mk('pointerup', 2, 620, 360);
  } catch (e) {
    threw = true;
    error = e && e.message ? e.message : String(e);
  } finally {
    restore();
    window.dispatchEvent(new Event('blur'));
  }
  return {
    restored,
    threw,
    error,
    before,
    after: window.SimpleCAD.state.view.scale,
    view: { ...window.SimpleCAD.state.view },
  };
});
await page.waitForTimeout(20);
const pinchMapIteratorErrors = consoleErrors.slice(pinchMapIteratorErrorsBefore);
check('2本指ピンチはMap values/iterator破損下でもズームを継続する',
  pinchMapIteratorRecovery.restored === true &&
  pinchMapIteratorRecovery.threw === false &&
  pinchMapIteratorRecovery.after > pinchMapIteratorRecovery.before &&
  pinchMapIteratorErrors.length === 0,
  JSON.stringify({ pinchMapIteratorRecovery, pinchMapIteratorErrors }));

