const malformedNumPanelInputErrorsBefore = consoleErrors.length;
const malformedNumPanelInput = await page.evaluate(() => {
  const patched = [];
  const patchValue = el => {
    if (!el) return false;
    const hadOwn = Object.prototype.hasOwnProperty.call(el, 'value');
    const original = hadOwn ? Object.getOwnPropertyDescriptor(el, 'value') : null;
    try {
      Object.defineProperty(el, 'value', {
        configurable: true,
        get() { throw new Error('bad numeric panel value get'); },
        set() { throw new Error('bad numeric panel value set'); },
      });
      patched.push({ el, hadOwn, original });
      return true;
    } catch (e) {
      return false;
    }
  };
  const run = fn => {
    try { fn(); return true; } catch (e) { return false; }
  };
  const fireInputChange = el => run(() => {
    el.dispatchEvent(new Event('input', { bubbles: true }));
    el.dispatchEvent(new Event('change', { bubbles: true }));
  });
  try {
    window.SimpleCAD.clearAll();
    window.SimpleCAD.addShape({ id: 'numBadRect', type: 'rect', x: 0, y: 0, w: 10, h: 12, stroke: '#000', strokeWidth: 1, fill: null, rot: 0 });
    window.SimpleCAD.select('numBadRect');
    const rectWidth = [...document.querySelectorAll('#numProps input[data-k]')].find(i => i.dataset.k === 'w');
    const rectDeg = document.querySelector('#numProps input[data-kdeg]');
    const rectPatched = patchValue(rectWidth);
    const degPatched = patchValue(rectDeg);
    const rectOk = fireInputChange(rectWidth);
    const degOk = fireInputChange(rectDeg);
    const syncOk = run(() => window.SimpleCAD.draw());
    const rect = window.SimpleCAD.state.shapes.find(s => s.id === 'numBadRect');

    window.SimpleCAD.addShape({ id: 'numBadText', type: 'text', x: 0, y: 0, text: 'before', fontSize: 16, stroke: '#000', strokeWidth: 1, fill: null });
    window.SimpleCAD.select('numBadText');
    const textInput = document.querySelector('#numProps input[data-ktext]');
    const textPatched = patchValue(textInput);
    const textOk = fireInputChange(textInput);
    const text = window.SimpleCAD.state.shapes.find(s => s.id === 'numBadText');

    window.SimpleCAD.clearAll();
    window.SimpleCAD.addShape({ id: 'numBadAngle', type: 'angle', vx: 0, vy: 0, x1: 20, y1: 0, x2: 0, y2: 20, stroke: '#000', strokeWidth: 1, fill: null });
    window.SimpleCAD.select('numBadAngle');
    const kang = document.querySelector('#numProps input[data-kang]');
    const kangPatched = patchValue(kang);
    const kangOk = fireInputChange(kang);
    const angle = window.SimpleCAD.state.shapes.find(s => s.id === 'numBadAngle');

    return {
      patched: [rectPatched, degPatched, textPatched, kangPatched].filter(Boolean).length,
      rectOk,
      degOk,
      syncOk,
      textOk,
      kangOk,
      rect: { w: rect && rect.w, rot: rect && rect.rot },
      text: text && text.text,
      angleFinite: angle && ['vx', 'vy', 'x1', 'y1', 'x2', 'y2'].every(k => Number.isFinite(angle[k])),
    };
  } finally {
    for (const item of patched.reverse()) {
      try {
        if (item.hadOwn && item.original) Object.defineProperty(item.el, 'value', item.original);
        else delete item.el.value;
      } catch (e) {}
    }
    try { window.SimpleCAD.draw(); } catch (e) {}
  }
});
