    result.widthPlain = isPlain('panelProxyRect', 'w', widthProxy);

    window.SimpleCAD.loadJSON({
      shapes: [{ id: 'panelProxyText', type: 'text', x: 0, y: 0, text: 'before', align: 'left', fontSize: 16, stroke: '#000', strokeWidth: 1, fill: null, layer: 'L1' }],
      layers: baseLayer,
      activeLayer: 'L1',
    });
    window.SimpleCAD.select('panelProxyText');
    const textProxy = installProxy('panelProxyText', ['text'], 'ignore');
    const textInput = document.querySelector('#numProps input[data-ktext]');
    textInput.value = 'Proxy復旧テキスト';
    try {
      textInput.dispatchEvent(new Event('input', { bubbles: true }));
      textInput.dispatchEvent(new Event('change', { bubbles: true }));
    } catch (e) {
      result.textOk = false;
    }
    result.text = shape('panelProxyText').text;
    result.textPlain = isPlain('panelProxyText', 'text', textProxy);

    const alignProxy = installProxy('panelProxyText', ['align']);
    try {
      document.querySelector('#numProps button[title="整列: center"]').click();
    } catch (e) {
      result.alignOk = false;
    }
    result.align = shape('panelProxyText').align;
    result.alignPlain = isPlain('panelProxyText', 'align', alignProxy);

    window.SimpleCAD.loadJSON({
      shapes: [{ id: 'panelProxyRot', type: 'rect', x: 0, y: 0, w: 10, h: 10, rot: 0, stroke: '#000', strokeWidth: 1, fill: null, layer: 'L1' }],
      layers: baseLayer,
      activeLayer: 'L1',
    });
    window.SimpleCAD.select('panelProxyRot');
