    const rotInput = document.querySelector('#numProps input[data-kdeg]');
    rotInput.value = '45';
    try {
      rotInput.dispatchEvent(new Event('input', { bubbles: true }));
      rotInput.dispatchEvent(new Event('change', { bubbles: true }));
    } catch (e) {
      result.rotOk = false;
    }
    result.rot = shape('panelProxyRot').rot;
