const scaleProxyRecoveryErrorsBefore = consoleErrors.length;
const scaleProxyRecovery = await page.evaluate(() => {
  const preserved = window.SimpleCAD.dumpJSON();
  const layer = [{ id: 'L1', name: 'レイヤー1', visible: true, locked: false }];
  const result = {
    rectOk: true,
    circleOk: true,
    polylineOk: true,
    rect: null,
    circle: null,
    polylinePoints: null,
    rectPlain: false,
    circlePlain: false,
    polylinePlain: false,
  };
  const installProxy = (id, blockedProps, mode = 'throw') => {
    const index = window.SimpleCAD.state.shapes.findIndex(s => s.id === id);
    const base = window.SimpleCAD.state.shapes[index];
    const blocked = new Set(blockedProps);
    const proxy = new Proxy(base, {
      set(target, prop, value) {
        if (blocked.has(String(prop))) {
          if (mode === 'ignore') return true;
          throw new Error('bad scale proxy set');
        }
        target[prop] = value;
        return true;
      },
    });
    window.SimpleCAD.state.shapes[index] = proxy;
    return proxy;
  };
  const shape = id => window.SimpleCAD.state.shapes.find(s => s.id === id) || {};
  const isPlain = (id, key, proxy) => {
    const current = shape(id);
    const desc = Object.getOwnPropertyDescriptor(current, key);
    return current !== proxy && !!desc && !desc.get && !desc.set && desc.writable === true;
  };
  try {
    window.SimpleCAD.loadJSON({
      shapes: [{ id: 'scaleProxyRect', type: 'rect', x: 10, y: 10, w: 20, h: 20, stroke: '#000', strokeWidth: 1, fill: null, layer: 'L1' }],
      layers: layer,
      activeLayer: 'L1',
    });
    const rectProxy = installProxy('scaleProxyRect', ['x', 'y', 'w', 'h']);
    try { window.SimpleCAD.transformAPI.scaleShapeAbout(rectProxy, 0, 0, 2, 3); } catch (e) { result.rectOk = false; }
    const rect = shape('scaleProxyRect');
    result.rect = { x: rect.x, y: rect.y, w: rect.w, h: rect.h };
    result.rectPlain = isPlain('scaleProxyRect', 'x', rectProxy) && isPlain('scaleProxyRect', 'w', rectProxy);

    window.SimpleCAD.loadJSON({
      shapes: [{ id: 'scaleProxyCircle', type: 'circle', cx: 10, cy: 10, r: 10, stroke: '#000', strokeWidth: 1, fill: null, layer: 'L1' }],
      layers: layer,
      activeLayer: 'L1',
    });
    const circleProxy = installProxy('scaleProxyCircle', ['cx', 'cy', 'r'], 'ignore');
    try { window.SimpleCAD.transformAPI.scaleShapeAbout(circleProxy, 0, 0, 2, 4); } catch (e) { result.circleOk = false; }
    const circle = shape('scaleProxyCircle');
    result.circle = { cx: circle.cx, cy: circle.cy, r: circle.r };
    result.circlePlain = isPlain('scaleProxyCircle', 'cx', circleProxy) && isPlain('scaleProxyCircle', 'r', circleProxy);

    window.SimpleCAD.loadJSON({
      shapes: [{ id: 'scaleProxyPoly', type: 'polyline', points: [{ x: 1, y: 1 }, { x: 4, y: 4 }], closed: false, stroke: '#000', strokeWidth: 1, fill: null, layer: 'L1' }],
      layers: layer,
      activeLayer: 'L1',
    });
    const polyProxy = installProxy('scaleProxyPoly', ['points']);
    try { window.SimpleCAD.transformAPI.scaleShapeAbout(polyProxy, 0, 0, 3, 2); } catch (e) { result.polylineOk = false; }
    result.polylinePoints = shape('scaleProxyPoly').points;
    result.polylinePlain = isPlain('scaleProxyPoly', 'points', polyProxy);
  } finally {
    window.SimpleCAD.loadJSON(preserved);
  }
  return result;
});
await page.waitForTimeout(20);
