const viewportResizeSanitize = await page.evaluate(() => {
  const cv = document.getElementById('cv');
  const ctx = cv.getContext('2d');
  const originalRect = cv.getBoundingClientRect;
  const originalDpr = Object.getOwnPropertyDescriptor(window, 'devicePixelRatio');
  const rect = (width, height) => ({ x: 0, y: 0, left: 0, top: 0, right: width, bottom: height, width, height });
  try {
    Object.defineProperty(window, 'devicePixelRatio', { value: Infinity, configurable: true });
    cv.getBoundingClientRect = () => rect(0, 0);
    window.dispatchEvent(new Event('resize'));
    const zero = { width: cv.width, height: cv.height, a: ctx.getTransform().a, d: ctx.getTransform().d };
    Object.defineProperty(window, 'devicePixelRatio', { value: 99, configurable: true });
    cv.getBoundingClientRect = () => rect(100000, 50000);
    window.dispatchEvent(new Event('resize'));
    const huge = { width: cv.width, height: cv.height, a: ctx.getTransform().a, d: ctx.getTransform().d };
    window.SimpleCAD.fitView();
    const view = { ...window.SimpleCAD.state.view };
    return { zero, huge, view };
  } finally {
    cv.getBoundingClientRect = originalRect;
    if (originalDpr) Object.defineProperty(window, 'devicePixelRatio', originalDpr);
    window.dispatchEvent(new Event('resize'));
  }
});
