const jsonLoadAtomicSafety = await page.evaluate(() => {
  const base = {
    shapes: [{ id: 'atomicKeep', type: 'rect', x: 10, y: 20, w: 30, h: 40, stroke: '#ffffff', strokeWidth: 2, fill: null, layer: 'L1' }],
    layers: [{ id: 'L1', name: 'レイヤー1', visible: true, locked: false }],
    activeLayer: 'L1',
    grid: { show: false, snap: false, osnap: false, step: 25 },
    style: { stroke: '#123456', strokeWidth: 4, fill: null, fontSize: 20, sides: 8, dash: 'dashed', dashOffset: 2, lineCap: 'round', lineJoin: 'round', miterLimit: 5 },
    ui: { light: true, precision: 3 },
    view: { scale: 3, offsetX: 15, offsetY: 25 },
    nextId: 77,
    nextLayerId: 2,
    nextGroupId: 1,
  };
  window.SimpleCAD.loadJSON(base);
  const before = window.SimpleCAD.dumpJSON();
  const incoming = {
    shapes: [{ id: 'atomicIncoming', type: 'line', x1: 0, y1: 0, x2: 10, y2: 10, stroke: '#abcdef', strokeWidth: 2, fill: null, layer: 'L1' }],
    layers: [{ id: 'L1', name: 'レイヤー1', visible: true, locked: false }],
    view: { scale: 5, offsetX: 33, offsetY: 44 },
    nextId: 5,
    nextLayerId: 2,
    nextGroupId: 1,
  };
  for (const key of ['grid', 'ui', 'style', 'activeLayer']) {
    Object.defineProperty(incoming, key, { enumerable: true, get() { throw new Error('bad ' + key); } });
  }
  let optionalOk = true;
  let optionalError = '';
  try { window.SimpleCAD.loadJSON(incoming); } catch (e) { optionalOk = false; optionalError = e.message; }
  const afterOptional = window.SimpleCAD.dumpJSON();
  let invalidThrew = false;
  let invalidError = '';
  try { window.SimpleCAD.loadJSON({ shapes: null, view: { scale: 99, offsetX: 99, offsetY: 99 } }); } catch (e) { invalidThrew = true; invalidError = e.message; }
  const afterInvalid = window.SimpleCAD.dumpJSON();
  return { before, afterOptional, afterInvalid, optionalOk, optionalError, invalidThrew, invalidError };
});
