  const light = document.getElementById('cLight');
  light.checked = true;
  fire(light, 'change');
  const changed = read();
  window.SimpleCAD.undo();
  const undoLight = read();
  window.SimpleCAD.undo();
  const undoSnap = read();
  window.SimpleCAD.undo();
  const undoStroke = read();
  window.SimpleCAD.redo();
  const redoStroke = read();
  window.SimpleCAD.redo();
  const redoSnap = read();
  window.SimpleCAD.redo();
