const undoBrokenTopLevelCollectionsErrorsBefore = consoleErrors.length;
const undoBrokenTopLevelCollections = await page.evaluate(() => {
  window.SimpleCAD.loadJSON({
    shapes: [],
    layers: [{ id: 'L1', name: 'レイヤー1', visible: true, locked: false }],
    activeLayer: 'L1',
  });
  window.SimpleCAD.addShape({ id: 'undoAccessorBase', type: 'rect', x: 0, y: 0, w: 10, h: 10, stroke: '#000', strokeWidth: 1, fill: null });
  const before = {
    count: window.SimpleCAD.shapeCount(),
    history: window.SimpleCAD.historyAPI.stats(),
  };
  const state = window.SimpleCAD.state;
  const installThrowingAccessor = key => {
    Object.defineProperty(state, key, {
      configurable: true,
      enumerable: true,
      get() { throw new Error('bad undo ' + key + ' get'); },
      set() { throw new Error('bad undo ' + key + ' set'); },
    });
  };
  installThrowingAccessor('shapes');
  installThrowingAccessor('layers');
  let undoOk = false, undoThrew = false;
  try { undoOk = window.SimpleCAD.undo(); } catch (e) { undoThrew = true; }
  const descriptors = {
    shapes: Object.getOwnPropertyDescriptor(state, 'shapes'),
    layers: Object.getOwnPropertyDescriptor(state, 'layers'),
  };
  return {
    before,
    undoOk,
    undoThrew,
    count: window.SimpleCAD.shapeCount(),
    history: window.SimpleCAD.historyAPI.stats(),
    layers: window.SimpleCAD.state.layers.map(l => l.id),
    plain:
      !!descriptors.shapes && !descriptors.shapes.get && !descriptors.shapes.set &&
      !!descriptors.layers && !descriptors.layers.get && !descriptors.layers.set,
  };
});
