const undoParseFailureErrorsBefore = consoleErrors.length;
const undoParseFailure = await page.evaluate(() => {
  window.SimpleCAD.loadJSON({
    shapes: [],
    layers: [{ id: 'L1', name: 'レイヤー1', visible: true, locked: false }],
    activeLayer: 'L1',
  });
  window.SimpleCAD.addShape({ id: 'undoParseBase', type: 'rect', x: 0, y: 0, w: 10, h: 10, stroke: '#000', strokeWidth: 1, fill: null });
  const before = {
    count: window.SimpleCAD.shapeCount(),
    history: window.SimpleCAD.historyAPI.stats(),
  };
  const originalParse = JSON.parse;
  let undoOk = true, undoThrew = false;
  try {
    JSON.parse = function (text, reviver) {
      if (String(text).includes('"shapes"')) throw new Error('forced history parse failure');
      return originalParse.call(this, text, reviver);
    };
    undoOk = window.SimpleCAD.undo();
  } catch (e) {
    undoThrew = true;
  } finally {
    JSON.parse = originalParse;
  }
  return {
    before,
    undoOk,
    undoThrew,
    count: window.SimpleCAD.shapeCount(),
    history: window.SimpleCAD.historyAPI.stats(),
    toast: document.getElementById('toast').textContent,
  };
});
const undoParseFailureErrors = consoleErrors.slice(undoParseFailureErrorsBefore);
