const autosaveStorageAccessFailure = await page.evaluate(() => {
  const originalDescriptor = Object.getOwnPropertyDescriptor(window, 'localStorage');
  const toastEl = document.getElementById('toast');
  const notice = document.getElementById('autosaveNotice');
  let accessAttempts = 0;
  let installed = false;
  try {
    window.SimpleCAD.clearAll();
    window.SimpleCAD.addShape({ id: 'blockedStorageSave', type: 'rect', x: 1, y: 2, w: 3, h: 4, stroke: '#000', strokeWidth: 1, fill: null });
    toastEl.textContent = '';
    Object.defineProperty(window, 'localStorage', {
      configurable: true,
      get() {
        accessAttempts++;
        throw new DOMException('storage disabled', 'SecurityError');
      },
    });
    installed = true;
    const saved = window.SimpleCAD.saveNow();
    const reloaded = window.SimpleCAD.reloadFromStore();
    return {
      installed,
      saved,
      reloaded,
      accessAttempts,
      msg: toastEl.textContent,
      noticeVisible: notice.hidden === false && notice.getAttribute('aria-hidden') === 'false',
    };
  } catch (e) {
    return { installed, threw: true, error: String(e && e.message || e), accessAttempts };
  } finally {
    if (installed) {
      if (originalDescriptor) Object.defineProperty(window, 'localStorage', originalDescriptor);
      else delete window.localStorage;
    }
    window.SimpleCAD.saveNow();
  }
});
