const wheelViewAutosave = await page.evaluate(async () => {
  const key = 'simplecad.autosave.v1';
  const cv = document.getElementById('cv');
  const dispatchWheel = (deltaY) => {
    const r = cv.getBoundingClientRect();
    cv.dispatchEvent(new WheelEvent('wheel', {
      bubbles: true,
      cancelable: true,
      deltaY,
      clientX: r.left + 200,
      clientY: r.top + 180,
    }));
  };
  const originalSetItem = Storage.prototype.setItem;
  const sameView = (a, b) => !!a && !!b &&
    Math.abs(a.scale - b.scale) < 1e-9 &&
    Math.abs(a.offsetX - b.offsetX) < 1e-9 &&
    Math.abs(a.offsetY - b.offsetY) < 1e-9;
  try {
    window.SimpleCAD.loadJSON({
      shapes: [{ id: 'wheelSaveBase', type: 'rect', x: 0, y: 0, w: 10, h: 10, stroke: '#000', strokeWidth: 1, fill: null }],
      layers: [{ id: 'L1', name: 'レイヤー1', visible: true, locked: false }],
      activeLayer: 'L1',
      view: { scale: 2, offsetX: 20, offsetY: 30 },
    });
    window.SimpleCAD.saveNow();
    let normalWrites = 0;
    Storage.prototype.setItem = function (...args) {
      normalWrites++;
      return originalSetItem.apply(this, args);
    };
    dispatchWheel(-120);
    const afterWheel = { ...window.SimpleCAD.state.view };
    await new Promise(resolve => setTimeout(resolve, 450));
    const storedAfterWheel = JSON.parse(localStorage.getItem(key) || '{}').view;
    Storage.prototype.setItem = originalSetItem;

    window.SimpleCAD.loadJSON({
      shapes: [{ id: 'wheelMaxBase', type: 'rect', x: 0, y: 0, w: 10, h: 10, stroke: '#000', strokeWidth: 1, fill: null }],
      layers: [{ id: 'L1', name: 'レイヤー1', visible: true, locked: false }],
      activeLayer: 'L1',
      view: { scale: 200, offsetX: 12, offsetY: 34 },
    });
    window.SimpleCAD.saveNow();
    let noOpWrites = 0;
    Storage.prototype.setItem = function (...args) {
      noOpWrites++;
      return originalSetItem.apply(this, args);
    };
    const beforeMaxWheel = { ...window.SimpleCAD.state.view };
    dispatchWheel(-120);
    const afterMaxWheel = { ...window.SimpleCAD.state.view };
    await new Promise(resolve => setTimeout(resolve, 450));
    const storedAfterMax = JSON.parse(localStorage.getItem(key) || '{}').view;
    return {
      normalWrites,
      noOpWrites,
      normalRestored: sameView(afterWheel, storedAfterWheel),
      maxUnchanged: sameView(beforeMaxWheel, afterMaxWheel) && sameView(beforeMaxWheel, storedAfterMax),
    };
  } finally {
    Storage.prototype.setItem = originalSetItem;
    window.SimpleCAD.saveNow();
  }
});
