    window.SimpleCAD.loadJSON({
      shapes: [],
      layers: [{ id: 'L1', name: 'レイヤー1', visible: true, locked: false }],
      activeLayer: 'L1',
      view: { scale: 2, offsetX: 0, offsetY: 0 },
    });
    window.SimpleCAD.state.grid.snap = false;
    window.SimpleCAD.setTool('text');
    fireTextClick(64, 260, 260);
    const displayBefore = input.style.display;
    input.value = 'ファイル選択直前の未確定テキスト';
    let attempts = 0;
