const gridCustomOptionCreate = await page.evaluate(() => {
  const gStep = document.getElementById('gStep');
  try {
    const custom = gStep && gStep.querySelector('option[data-custom-step]');
    if (custom) custom.remove();
  } catch (e) {}
  const originalCreateElement = document.createElement;
  let blocked = 0;
  const run = fn => {
    try { fn(); return { ok: true }; } catch (e) { return { ok: false, error: e && e.message }; }
  };
  try {
    document.createElement = function (tagName, ...args) {
      if (String(tagName).toLowerCase() === 'option') {
        blocked++;
        throw new Error('grid option create failed');
      }
      return originalCreateElement.call(this, tagName, ...args);
    };
    const loadResult = run(() => window.SimpleCAD.loadJSON({
      shapes: [],
      layers: [{ id: 'L1', name: 'レイヤー1', visible: true, locked: false }],
      activeLayer: 'L1',
      grid: { show: true, snap: true, osnap: true, step: 37 },
      ui: { light: false, precision: 1 },
    }));
    return {
      blocked,
      loadResult,
      step: window.SimpleCAD.state.grid.step,
      customOptions: document.querySelectorAll('#gStep option[data-custom-step]').length,
    };
  } finally {
    document.createElement = originalCreateElement;
  }
});
