const malformedArrayInputValueErrorsBefore = consoleErrors.length;
const malformedArrayInputValue = await page.evaluate(() => {
  const ids = ['arRows', 'arCols', 'arDx', 'arDy'];
  const patched = [];
  const run = fn => {
    try { fn(); return true; } catch (e) { return false; }
  };
  const malformedAttrs = { arRows: 'bad', arCols: '0', arDx: 'Infinity', arDy: '-Infinity' };
  for (const [id, value] of Object.entries(malformedAttrs)) {
    try { document.getElementById(id).setAttribute('value', value); } catch (e) {}
  }
  for (const id of ids) {
    const el = document.getElementById(id);
    if (!el) continue;
    const hadOwn = Object.prototype.hasOwnProperty.call(el, 'value');
    const original = hadOwn ? Object.getOwnPropertyDescriptor(el, 'value') : null;
    try {
      Object.defineProperty(el, 'value', {
        configurable: true,
        get() { throw new Error('bad array input value get'); },
        set() { throw new Error('bad array input value set'); },
      });
      patched.push({ el, hadOwn, original });
    } catch (e) {}
  }
  try {
    window.SimpleCAD.clearAll();
    window.SimpleCAD.addShape({ id: 'arValueBad', type: 'rect', x: 0, y: 0, w: 10, h: 10, stroke: '#fff', strokeWidth: 1, fill: null });
    window.SimpleCAD.select('arValueBad');
    const openOk = run(() => document.querySelector('#selActions button[data-act=array]').click());
    const createOk = run(() => document.getElementById('arrayOk').click());
    const shapes = window.SimpleCAD.dumpJSON().shapes;
    return {
      patched: patched.length,
      openOk,
      createOk,
      hidden: document.getElementById('arrayDlg').getAttribute('aria-hidden'),
      count: shapes.length,
      id: shapes[0] && shapes[0].id,
    };
  } finally {
    for (const item of patched.reverse()) {
      try {
        if (item.hadOwn && item.original) Object.defineProperty(item.el, 'value', item.original);
        else delete item.el.value;
      } catch (e) {}
    }
    try { document.getElementById('arrayDlg').style.display = 'none'; } catch (e) {}
  }
});
await page.waitForTimeout(20);
const malformedArrayInputValueErrors = consoleErrors.slice(malformedArrayInputValueErrorsBefore);
check('壊れた配列入力valueでも配列作成操作は安全値で落ちない',
  malformedArrayInputValue.patched === 4 &&
  malformedArrayInputValue.openOk === true &&
  malformedArrayInputValue.createOk === true &&
  malformedArrayInputValue.hidden === 'true' &&
  malformedArrayInputValue.count === 1 &&
  malformedArrayInputValue.id === 'arValueBad' &&
  malformedArrayInputValueErrors.length === 0,
  JSON.stringify({ malformedArrayInputValue, malformedArrayInputValueErrors }));

