const selectedOpsIteratorRecoveryErrorsBefore = consoleErrors.length;
const selectedOpsIteratorRecovery = await page.evaluate(() => {
  const preserved = window.SimpleCAD.dumpJSON();
  const originalIterator = Object.getOwnPropertyDescriptor(Array.prototype, Symbol.iterator);
  const shouldBreak = arr => {
    try {
      const len = Number(arr && arr.length);
      if (!Number.isFinite(len) || len <= 0) return false;
      for (let i = 0; i < len; i++) {
        const item = arr[i];
        if (item && typeof item === 'object' && String(item.id || '').indexOf('iterSelected') === 0) return true;
      }
    } catch (e) {}
    return false;
  };
  const run = fn => {
    try { return { ok: true, value: fn() }; } catch (e) { return { ok: false, error: e && e.message }; }
  };
  const byId = id => window.SimpleCAD.state.shapes.find(s => s.id === id) || null;
  try {
    window.SimpleCAD.loadJSON({
      layers: [
        { id: 'L1', name: '選択iterator元', visible: true, locked: false },
        { id: 'L2', name: '選択iterator先', visible: true, locked: false },
      ],
      activeLayer: 'L1',
      shapes: [
        { id: 'iterSelectedRect', type: 'rect', x: 0, y: 0, w: 10, h: 10, stroke: '#000000', strokeWidth: 1, fill: null, layer: 'L1' },
        { id: 'iterSelectedCircle', type: 'circle', cx: 30, cy: 5, r: 5, stroke: '#000000', strokeWidth: 1, fill: null, layer: 'L1' },
      ],
    });
    window.SimpleCAD.selectMany(['iterSelectedRect', 'iterSelectedCircle']);
    Object.defineProperty(Array.prototype, Symbol.iterator, {
      configurable: true,
      writable: true,
      value: function () {
        if (shouldBreak(this)) throw new Error('broken selected shape iterator');
        return originalIterator.value.call(this);
      },
    });

    window.SimpleCAD.state.style.stroke = '#123456';
    window.SimpleCAD.state.style.strokeWidth = 3;
    window.SimpleCAD.state.style.fill = '#abcdef';
    window.SimpleCAD.state.style.dash = 'dashed';
    const apply = run(() => { document.getElementById('btnApply').click(); return true; });
    const afterStyle = {
      rectStroke: byId('iterSelectedRect')?.stroke,
      rectStrokeWidth: byId('iterSelectedRect')?.strokeWidth,
      rectFill: byId('iterSelectedRect')?.fill,
      circleDash: byId('iterSelectedCircle')?.dash,
    };

    window.SimpleCAD.state.activeLayer = 'L2';
    const move = run(() => { window.SimpleCAD.layerAPI.moveSel(); return true; });
    const afterMove = {
      rectLayer: byId('iterSelectedRect')?.layer,
      circleLayer: byId('iterSelectedCircle')?.layer,
    };

    const lock = run(() => { window.SimpleCAD.lockAPI.toggle(); return true; });
    const afterLock = {
      rectLocked: byId('iterSelectedRect')?.locked === true,
      circleLocked: byId('iterSelectedCircle')?.locked === true,
    };
    const unlock = run(() => { window.SimpleCAD.lockAPI.toggle(); return true; });

    window.SimpleCAD.selectMany(['iterSelectedRect', 'iterSelectedCircle']);
    document.getElementById('arRows').value = '1';
    document.getElementById('arCols').value = '2';
    document.getElementById('arDx').value = '15';
    document.getElementById('arDy').value = '0';
    const array = run(() => { document.getElementById('arrayOk').click(); return true; });
    const ids = [];
    const shapes = window.SimpleCAD.state.shapes;
    for (let i = 0; i < shapes.length; i++) ids.push(shapes[i].id);
    const duplicates = [];
    for (let i = 0; i < shapes.length; i++) {
      if (shapes[i].type === 'rect' && shapes[i].x === 15 && shapes[i].y === 0) duplicates.push(shapes[i].id);
      if (shapes[i].type === 'circle' && shapes[i].cx === 45 && shapes[i].cy === 5) duplicates.push(shapes[i].id);
    }

    return {
      ok: true,
      apply,
      afterStyle,
      move,
      afterMove,
      lock,
      afterLock,
      unlock,
      array,
      count: window.SimpleCAD.shapeCount(),
      ids,
      duplicateCount: duplicates.length,
    };
  } catch (e) {
    return { ok: false, message: e && e.message };
  } finally {
    if (originalIterator) Object.defineProperty(Array.prototype, Symbol.iterator, originalIterator);
    window.SimpleCAD.loadJSON(preserved);
  }
});
