const fullscreenFailureErrorsBefore = consoleErrors.length;
const fullscreenFailureNotifications = await page.evaluate(async () => {
  const app = document.getElementById('app');
  const btn = document.getElementById('btnFull');
  const toastEl = document.getElementById('toast');
  const restore = [];
  const setOwn = (obj, prop, descriptor) => {
    const hadOwn = Object.prototype.hasOwnProperty.call(obj, prop);
    const original = Object.getOwnPropertyDescriptor(obj, prop);
    Object.defineProperty(obj, prop, descriptor);
    restore.push(() => {
      if (hadOwn) Object.defineProperty(obj, prop, original);
      else delete obj[prop];
    });
  };
  try {
    setOwn(app, 'requestFullscreen', { configurable: true, value() { throw new Error('request failed'); } });
    btn.click();
    const syncRequest = toastEl.textContent;

    setOwn(app, 'requestFullscreen', { configurable: true, value: undefined });
    btn.click();
    const unsupportedRequest = toastEl.textContent;

    setOwn(document, 'fullscreenElement', { configurable: true, get() { return app; } });
    setOwn(document, 'exitFullscreen', { configurable: true, value() { return Promise.reject(new Error('exit failed')); } });
    btn.click();
    await new Promise(resolve => setTimeout(resolve, 20));
    const rejectedExit = toastEl.textContent;

    return { syncRequest, unsupportedRequest, rejectedExit };
  } finally {
    while (restore.length) restore.pop()();
  }
});
await page.waitForTimeout(20);
const fullscreenFailureErrors = consoleErrors.slice(fullscreenFailureErrorsBefore);
check('全画面API失敗/非対応時は落とさず用途別に通知する',
  fullscreenFailureNotifications.syncRequest.includes('全画面表示に失敗') &&
  fullscreenFailureNotifications.unsupportedRequest.includes('全画面表示に対応') &&
  fullscreenFailureNotifications.rejectedExit.includes('全画面解除に失敗') &&
  fullscreenFailureErrors.length === 0,
  JSON.stringify({ fullscreenFailureNotifications, fullscreenFailureErrors }));
const asyncSchedulerCallbackFailureErrorsBefore = consoleErrors.length;
const asyncSchedulerCallbackFailure = await page.evaluate(async () => {
  const originalSetTransform = CanvasRenderingContext2D.prototype.setTransform;
  const originalSetTimeout = window.setTimeout;
  const originalRequestAnimationFrame = window.requestAnimationFrame;
  const delay = ms => new Promise(resolve => originalSetTimeout.call(window, resolve, ms));
  const recoverErrors = [];
  const recover = () => {
    CanvasRenderingContext2D.prototype.setTransform = originalSetTransform;
    window.setTimeout = originalSetTimeout;
    window.requestAnimationFrame = originalRequestAnimationFrame;
    try { window.dispatchEvent(new Event('resize')); } catch (e) { recoverErrors.push(e && e.message || ''); }
  };
  const runScenario = async (mode) => {
    let setTransformCalls = 0;
    let timeoutCalls = 0;
    let rafCalls = 0;
    recover();
    CanvasRenderingContext2D.prototype.setTransform = function () {
      setTransformCalls++;
      throw new Error(mode + ' resize failed');
    };
    if (mode === 'timer') {
      window.setTimeout = function (fn, ms, ...rest) {
        if (ms === 50) timeoutCalls++;
        return originalSetTimeout.call(window, fn, ms === 50 ? 0 : ms, ...rest);
      };
    } else {
      window.setTimeout = function (fn, ms, ...rest) {
        if (ms === 50) {
          timeoutCalls++;
          throw new Error('timer blocked');
        }
        return originalSetTimeout.call(window, fn, ms, ...rest);
      };
      window.requestAnimationFrame = function (fn) {
        rafCalls++;
        return originalSetTimeout.call(window, () => fn(0), 0);
      };
    }
    try {
      document.dispatchEvent(new Event('fullscreenchange'));
      await delay(30);
      return { setTransformCalls, timeoutCalls, rafCalls };
    } finally {
      recover();
    }
  };
  try {
    const timer = await runScenario('timer');
    const raf = await runScenario('raf');
    return { timer, raf, recoverErrors };
  } finally {
    recover();
  }
});
await page.waitForTimeout(20);
const asyncSchedulerCallbackFailureErrors = consoleErrors.slice(asyncSchedulerCallbackFailureErrorsBefore);
check('タイマー/RAF予約後のコールバック例外はpageerrorへ漏れない',
  asyncSchedulerCallbackFailure.timer.timeoutCalls >= 1 &&
  asyncSchedulerCallbackFailure.timer.setTransformCalls >= 1 &&
  asyncSchedulerCallbackFailure.raf.timeoutCalls >= 1 &&
  asyncSchedulerCallbackFailure.raf.rafCalls === 1 &&
  asyncSchedulerCallbackFailure.raf.setTransformCalls >= 1 &&
  asyncSchedulerCallbackFailure.recoverErrors.length === 0 &&
  asyncSchedulerCallbackFailureErrors.length === 0,
  JSON.stringify({ asyncSchedulerCallbackFailure, asyncSchedulerCallbackFailureErrors }));

const eventHandlerCallbackFailureErrorsBefore = consoleErrors.length;
const eventHandlerCallbackFailure = await page.evaluate(async () => {
  const api = window.SimpleCAD?.safetyAPI;
  const el = document.createElement('button');
  const preserve = document.createElement('button');
  let listenerCalls = 0;
  let listenerThisOk = false;
  let handlerCalls = 0;
  let handlerThisOk = false;
  let objectThisOk = false;
  const objectListener = {
    calls: 0,
    handleEvent() {
      this.calls++;
      objectThisOk = this === objectListener;
      throw new Error('object listener failed');
    },
  };
  const addResult = api?.addEventListener(el, 'click', function () {
    listenerCalls++;
    listenerThisOk = this === el;
    throw new Error('event listener failed');
  });
  const objectResult = api?.addEventListener(el, 'click', objectListener);
  const handlerResult = api?.setHandler(el, 'onclick', function () {
    handlerCalls++;
    handlerThisOk = this === el;
    throw new Error('onclick failed');
  });
  el.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true }));
  const preserveResult = api?.setHandler(preserve, 'onclick', function () {
    return false;
  });
  const falseReturn = preserve.onclick(new MouseEvent('click', { cancelable: true }));
  const clearResult = api?.setHandler(preserve, 'onclick', null);
  await new Promise(resolve => setTimeout(resolve, 20));
  return {
    hasAPI: Boolean(api),
    addResult,
    objectResult,
    handlerResult,
    listenerCalls,
    listenerThisOk,
    objectCalls: objectListener.calls,
    objectThisOk,
    handlerCalls,
    handlerThisOk,
    preserveResult,
    falseReturn,
    clearResult,
    cleared: preserve.onclick === null,
  };
});
await page.waitForTimeout(20);
const eventHandlerCallbackFailureErrors = consoleErrors.slice(eventHandlerCallbackFailureErrorsBefore);
check('イベント/onclickハンドラ例外はpageerrorへ漏れない',
  eventHandlerCallbackFailure.hasAPI &&
  eventHandlerCallbackFailure.addResult === true &&
  eventHandlerCallbackFailure.objectResult === true &&
  eventHandlerCallbackFailure.handlerResult === true &&
  eventHandlerCallbackFailure.listenerCalls === 1 &&
  eventHandlerCallbackFailure.listenerThisOk &&
  eventHandlerCallbackFailure.objectCalls === 1 &&
  eventHandlerCallbackFailure.objectThisOk &&
  eventHandlerCallbackFailure.handlerCalls === 1 &&
  eventHandlerCallbackFailure.handlerThisOk &&
  eventHandlerCallbackFailure.preserveResult === true &&
  eventHandlerCallbackFailure.falseReturn === false &&
  eventHandlerCallbackFailure.clearResult === true &&
  eventHandlerCallbackFailure.cleared === true &&
  eventHandlerCallbackFailureErrors.length === 0,
  JSON.stringify({ eventHandlerCallbackFailure, eventHandlerCallbackFailureErrors }));

