// --- CE: DXFレイヤー(code 8)を SimpleCAD レイヤーへマッピング ---
const dxfLayers = await page.evaluate(() => {
  window.SimpleCAD.clearAll();
  const dxf = ['0', 'SECTION', '2', 'ENTITIES',
    '0', 'LINE', '8', 'WALL', '10', '0', '20', '0', '11', '10', '21', '0',
    '0', 'LINE', '8', 'DOOR', '10', '0', '20', '0', '11', '5', '21', '5',
    '0', 'ENDSEC', '0', 'EOF'].join('\n');
  window.SimpleCAD.importVector(dxf, 'dxf');
  const layerNames = window.SimpleCAD.state.layers.map(l => l.name);
  const shapeLayers = window.SimpleCAD.state.shapes.map(s => { const l = window.SimpleCAD.state.layers.find(x => x.id === s.layer); return l ? l.name : null; });
  return { layerNames, shapeLayers };
});
check('DXFレイヤー名で層を作成し図形を割当', dxfLayers.layerNames.includes('WALL') && dxfLayers.layerNames.includes('DOOR') && dxfLayers.shapeLayers.includes('WALL') && dxfLayers.shapeLayers.includes('DOOR'), JSON.stringify(dxfLayers));
const dxfSpecialLayers = await page.evaluate(() => {
  window.SimpleCAD.clearAll();
  const dxf = ['0', 'SECTION', '2', 'ENTITIES',
    '0', 'LINE', '8', '__proto__', '10', '0', '20', '0', '11', '10', '21', '0',
    '0', 'LINE', '8', 'constructor', '10', '0', '20', '0', '11', '5', '21', '5',
    '0', 'ENDSEC', '0', 'EOF'].join('\n');
  const added = window.SimpleCAD.importVector(dxf, 'dxf');
  const layerNames = window.SimpleCAD.state.layers.map(l => l.name);
  const shapeLayers = window.SimpleCAD.state.shapes.map(s => {
    const l = window.SimpleCAD.state.layers.find(x => x.id === s.layer);
    return l ? l.name : null;
  });
  return { added, layerNames, shapeLayers, protoPolluted: ({}).polluted };
});
  check('DXF特殊レイヤー名でも安全に層を作成し図形を割当',
    dxfSpecialLayers.added === 2 &&
    dxfSpecialLayers.layerNames.includes('__proto__') &&
    dxfSpecialLayers.layerNames.includes('constructor') &&
    dxfSpecialLayers.shapeLayers.includes('__proto__') &&
    dxfSpecialLayers.shapeLayers.includes('constructor') &&
    dxfSpecialLayers.protoPolluted === undefined,
    JSON.stringify(dxfSpecialLayers));
  const dxfLayerStates = await page.evaluate(() => {
    window.SimpleCAD.clearAll();
    const dxf = ['0', 'SECTION', '2', 'TABLES',
      '0', 'TABLE', '2', 'LAYER',
      '0', 'LAYER', '2', 'OFF_LAYER', '70', '0', '62', '-1', '6', 'Continuous',
      '0', 'LAYER', '2', 'FROZEN_LAYER', '70', '1', '62', '3', '6', 'Continuous',
      '0', 'LAYER', '2', 'LOCKED_LAYER', '70', '4', '62', '5', '6', 'Continuous',
      '0', 'ENDTAB',
      '0', 'ENDSEC',
      '0', 'SECTION', '2', 'ENTITIES',
      '0', 'LINE', '8', 'OFF_LAYER', '10', '0', '20', '0', '11', '10', '21', '0',
      '0', 'LINE', '8', 'FROZEN_LAYER', '10', '0', '20', '10', '11', '10', '21', '10',
      '0', 'LINE', '8', 'LOCKED_LAYER', '10', '0', '20', '20', '11', '10', '21', '20',
      '0', 'ENDSEC', '0', 'EOF'].join('\n');
    const added = window.SimpleCAD.importVector(dxf, 'dxf');
    const layers = Object.fromEntries(window.SimpleCAD.state.layers.map(l => [l.name, {
      visible: l.visible,
      locked: l.locked,
    }]));
    const shapeLayers = window.SimpleCAD.state.shapes.map(s => {
      const l = window.SimpleCAD.state.layers.find(x => x.id === s.layer);
      return l ? l.name : null;
    });
    return { added, layers, shapeLayers, svg: window.SimpleCAD.buildSVGString() };
  });
  check('DXF LAYERのOFF/FROZEN/LOCKED状態を取り込む',
    dxfLayerStates.added === 3 &&
    dxfLayerStates.layers.OFF_LAYER.visible === false &&
    dxfLayerStates.layers.OFF_LAYER.locked === false &&
    dxfLayerStates.layers.FROZEN_LAYER.visible === false &&
    dxfLayerStates.layers.FROZEN_LAYER.locked === false &&
    dxfLayerStates.layers.LOCKED_LAYER.visible === true &&
    dxfLayerStates.layers.LOCKED_LAYER.locked === true &&
    dxfLayerStates.shapeLayers.includes('OFF_LAYER') &&
    dxfLayerStates.shapeLayers.includes('FROZEN_LAYER') &&
    dxfLayerStates.shapeLayers.includes('LOCKED_LAYER') &&
    dxfLayerStates.svg.includes('<line'),
    JSON.stringify(dxfLayerStates));
  const dxfLayerIteratorRecoveryErrorsBefore = consoleErrors.length;
  const dxfLayerIteratorRecovery = await page.evaluate(() => {
    const originalIterator = Object.getOwnPropertyDescriptor(Array.prototype, Symbol.iterator);
    const isLayerArray = arr => {
      try {
        const len = Number(arr && arr.length);
        if (!Number.isFinite(len) || len <= 0) return false;
        for (let i = 0; i < len; i++) {
          const item = arr[i];
          if (item && typeof item === 'object' &&
            Object.prototype.hasOwnProperty.call(item, 'name') &&
            Object.prototype.hasOwnProperty.call(item, 'visible') &&
            Object.prototype.hasOwnProperty.call(item, 'locked')) return true;
        }
      } catch (e) {}
      return false;
    };
    try {
      window.SimpleCAD.clearAll();
      Object.defineProperty(Array.prototype, Symbol.iterator, {
        configurable: true,
        writable: true,
        value: function () {
          if (isLayerArray(this)) throw new Error('bad dxf layer array iterator');
          return originalIterator.value.call(this);
        },
      });
      const dxf = ['0', 'SECTION', '2', 'TABLES',
        '0', 'TABLE', '2', 'LAYER',
        '0', 'LAYER', '2', 'ITER_WALL', '70', '0', '62', '3',
        '0', 'LAYER', '2', 'ITER_LOCKED', '70', '4', '62', '5',
        '0', 'ENDTAB', '0', 'ENDSEC',
        '0', 'SECTION', '2', 'ENTITIES',
        '0', 'LINE', '8', 'ITER_WALL', '10', '0', '20', '0', '11', '10', '21', '0',
        '0', 'LINE', '8', 'ITER_LOCKED', '10', '0', '20', '10', '11', '10', '21', '10',
        '0', 'ENDSEC', '0', 'EOF'].join('\n');
      const added = window.SimpleCAD.importVector(dxf, 'dxf');
      const layerNames = [];
      const shapeLayers = [];
      const layers = window.SimpleCAD.state.layers;
      const shapes = window.SimpleCAD.state.shapes;
      let lockedLayerState = null;
      for (let i = 0; i < layers.length; i++) {
        layerNames[layerNames.length] = layers[i].name;
        if (layers[i].name === 'ITER_LOCKED') lockedLayerState = { visible: layers[i].visible, locked: layers[i].locked };
      }
      for (let si = 0; si < shapes.length; si++) {
        let name = null;
        for (let li = 0; li < layers.length; li++) {
          if (layers[li].id === shapes[si].layer) { name = layers[li].name; break; }
        }
        shapeLayers[shapeLayers.length] = name;
      }
      return { ok: true, added, layerNames, shapeLayers, lockedLayerState };
    } catch (e) {
      return { ok: false, message: e && e.message };
    } finally {
      try {
        if (originalIterator) Object.defineProperty(Array.prototype, Symbol.iterator, originalIterator);
        else delete Array.prototype[Symbol.iterator];
      } catch (e) {}
    }
  });
  const dxfLayerIteratorRecoveryErrors = consoleErrors.slice(dxfLayerIteratorRecoveryErrorsBefore);
  check('DXFレイヤー取り込みは配列iterator破損下でも層作成と割当を維持する',
    dxfLayerIteratorRecovery.ok === true &&
    dxfLayerIteratorRecovery.added === 2 &&
    dxfLayerIteratorRecovery.layerNames.includes('ITER_WALL') &&
    dxfLayerIteratorRecovery.layerNames.includes('ITER_LOCKED') &&
    dxfLayerIteratorRecovery.shapeLayers.includes('ITER_WALL') &&
    dxfLayerIteratorRecovery.shapeLayers.includes('ITER_LOCKED') &&
    dxfLayerIteratorRecovery.lockedLayerState?.locked === true &&
    dxfLayerIteratorRecoveryErrors.length === 0,
    JSON.stringify({ dxfLayerIteratorRecovery, dxfLayerIteratorRecoveryErrors }));

  // ---- 印刷(実寸) ----
const printErrorsBefore = consoleErrors.length;
const printResult = await page.evaluate(async () => {
  window.SimpleCAD.clearAll();
  window.SimpleCAD.addShape({ id: 'printRect', type: 'rect', x: 0, y: 0, w: 50, h: 30, stroke: '#000', strokeWidth: 1, fill: null });
  const svg = window.SimpleCAD.buildSVGString();
  const docHtml = window.SimpleCAD.buildPrintDocument(svg);
  const countFrames = () => document.querySelectorAll('iframe').length;
  const framesBefore = countFrames();
  const ret = window.SimpleCAD.printDrawing();
  const framesDuring = countFrames();
  await new Promise(r => setTimeout(r, 500));   // onload/300msタイマーでの印刷発火を待つ
  await new Promise(r => setTimeout(r, 1700));  // 1500msの後始末を待つ
  const framesAfterCleanup = countFrames();
  // 図形が無いときはfalseを返す
  window.SimpleCAD.clearAll();
  const emptyRet = window.SimpleCAD.printDrawing();
  return {
    svgHasMm: /width="[\d.]+mm"/.test(svg) && /height="[\d.]+mm"/.test(svg),
    docHasPage: docHtml.includes('@page') && docHtml.includes('size:auto'),
    docHasSvg: docHtml.includes('<svg') && docHtml.includes('</svg>'),
    docHasDoctype: docHtml.toLowerCase().includes('<!doctype html>'),
    ret, framesBefore, framesDuring, framesAfterCleanup, emptyRet,
  };
});
const printErrors = consoleErrors.slice(printErrorsBefore);
check('印刷: buildPrintDocumentは@page/mm/白背景の実寸SVG文書を生成する',
  printResult.docHasDoctype && printResult.docHasPage && printResult.docHasSvg && printResult.svgHasMm,
  JSON.stringify(printResult));
check('印刷: printDrawingはiframeを生成し印刷後に後始末する(図形無しはfalse)',
  printResult.ret === true &&
  printResult.framesDuring === printResult.framesBefore + 1 &&
  printResult.framesAfterCleanup === printResult.framesBefore &&
  printResult.emptyRet === false &&
  printErrors.length === 0,
  JSON.stringify({ printResult, printErrors }));

// --- 展開図(ネット)生成: 直方体・円柱・円錐 ---
async function genNet(type, withDim) {
  await page.evaluate(() => window.SimpleCAD.clearAll());
  await page.click('#btnNet');
  await page.waitForFunction(() => document.getElementById('netDlg').style.display === 'flex');
  await page.selectOption('#netType', type);
  await page.evaluate((wd) => { document.getElementById('netDimChk').checked = wd; }, withDim);
  await page.click('#netOk');
  await page.waitForFunction(() => document.getElementById('netDlg').style.display === 'none');
  return await page.evaluate(() => {
    const dump = window.SimpleCAD.dumpJSON();
    const shapes = dump.shapes || [];
    const types = {}; let dashed = 0;
    for (const s of shapes) { types[s.type] = (types[s.type] || 0) + 1; if (s.dash === 'dashed') dashed++; }
    return { sc: window.SimpleCAD.shapeCount(), types, dashed };
  });
}
const netBox = await genNet('box', true);
check('展開図: 直方体は6面の展開(折り線5本=破線)と寸法3本を生成する',
  netBox.sc >= 19 && netBox.dashed >= 5 && (netBox.types.dim || 0) >= 3,
  JSON.stringify(netBox));
const netCyl = await genNet('cylinder', true);
check('展開図: 円柱は側面矩形(上下=折り線)と上下2円・寸法を生成する',
  (netCyl.types.line || 0) >= 4 && (netCyl.types.circle || 0) === 2 && netCyl.dashed >= 2 && (netCyl.types.dim || 0) >= 1,
  JSON.stringify(netCyl));
const netCone = await genNet('cone', true);
check('展開図: 円錐は扇形(母線2本+弧)と底面円を生成する',
  (netCone.types.line || 0) >= 2 && (netCone.types.polyline || 0) >= 1 && (netCone.types.circle || 0) === 1,
  JSON.stringify(netCone));
const netNoDim = await genNet('cylinder', false);
check('展開図: 寸法OFFでは寸法線を生成しない',
  (netNoDim.types.dim || 0) === 0,
  JSON.stringify(netNoDim));
await page.evaluate(() => window.SimpleCAD.clearAll());

  // 後始末
check('最終的にコンソールエラーなし', consoleErrors.length === 0, consoleErrors.join(' | '));

await browser.close();

console.log('\n==== SimpleCAD 検証結果 ====');
console.log(results.join('\n'));
console.log(`\n合計: ${pass} passed, ${fail} failed`);
process.exit(fail === 0 ? 0 : 1);
